var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"역시 봉인 사슬과 잔해의 상성은 좋지 않군.","JPN":"やはり封印の鎖と残骸の相性は良くないな。","ENG":"As expected, the Remains are no match against the Sealing Chain.","TWN":"果然封印鎖鏈對殘骸有克制作用。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……어쩔 수 없나?","JPN":"……仕方ないか。","ENG":"…We can't help it.","TWN":"……沒有辦法嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"여기는 철학부. 파편 회수 임무는 실패다. 작전 포인트까지 퇴각한다.","JPN":"こちら、哲学部。破片回収任務は失敗だ。作戦ポイントまで退却する。","ENG":"This is the Department of Philosophy. Mission to retrieve the Fragment failed. Retreating back to the operation point.","TWN":"這裡是哲學院，碎片回收任務失敗。我們將撤退到作戰點。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"모두 연막탄을 살포해! 퇴각한다!","JPN":"みんな、煙幕を使え！　退散だ！","ENG":"Use the smokescreens and retreat!","TWN":"放煙霧彈！撤退！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 자식이 어딜 도망치려고!","JPN":"させるかよ！","ENG":"Where do you think you're going?!","TWN":"喂！可惡！這些傢伙要跑了！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……콜록! 콜록!","JPN":"……ゲホッ！　ゲホッ！","ENG":"...*Cough!* *Cough!*","TWN":"……咳咳！咳咳！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참, 튀려면 그냥 튈 것이지 무슨 연막까지 뿌리고 난리야?","JPN":"ったく、大人しく逃げればいいのに、煙幕ってやりすぎだろ？","ENG":"Blimey, what's with the smokescreens? They could've just run away!","TWN":"真是的，想跑就跑，丟什麼煙霧彈？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"괘, 괜찮으세요?","JPN":"だ、大丈夫ですか？","ENG":"A-are you all right?","TWN":"你，你沒事吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저…… 그러니까, 으음.","JPN":"あの……えっと、あの……","ENG":"I... Um, w-well...","TWN":"我……那個，沒事。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"신경 쓰지 마. 어차피 놔주는 것까지가 작전이니까.","JPN":"気にするな。どうせ逃がしてやるところまでが作戦だからな。","ENG":"Don't mind me. It was part of the plan to let them go anyway.","TWN":"別在意，反正故意放他們走也是作戰中的一部分。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"네? 작전…… 이라고요?","JPN":"え？　作戦……ですか？","ENG":"Huh? Did you say... plan?","TWN":"什麼？作戰……嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아무튼 그런 게 있어. 그보다 너!","JPN":"そういうこと。それより、お前！","ENG":"Nothing you should be concerned about. But you!","TWN":"總之，我自有想法。倒是你啊——！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"네? 네!","JPN":"はい？　あっ、はい！","ENG":"Huh? Yes?!","TWN":"啊？是！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당장 아카데미로 돌아가.","JPN":"今すぐアカデミーに戻れ。","ENG":"Go back to the Academy right now.","TWN":"馬上給我回學院。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"돌아가서 거기 이사장한테 오늘 있었던 일 하나도 빠짐없이 말하고, 보호 요청해.","JPN":"戻ってそこの理事長に今日の出来事を全部話して、保護を要請しろ。","ENG":"Go back and tell the chairwoman everything that just happened in detail, then ask for protection.","TWN":"回去後向理事長一五一十地說明今天發生的事，並且申請保護。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 당분간 아카데미 밖으로 한 발짝도 나오지 마. 알겠어?","JPN":"それからしばらくはアカデミーの外に一歩も出ないこと。いいな？","ENG":"Also, don't you ever think about setting foot outside of school grounds for a while, you hear me?","TWN":"還有，暫時不要離開學院一步，明白了嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"네? 네에?","JPN":"え？　ええっ？","ENG":"Huh? What?","TWN":"嗯？什麼？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터 아카데미는 그라운드 원에서 관리국 본부 다음으로 안전한 곳이야.","JPN":"カウンターアカデミーはグラウンド・ワンの中で管理局の次に安全なところだ。","ENG":"Counter Academy is the safest place to be in Ground One, right after the Administration headquarters.","TWN":"制裁者學院的安全程度在G1裡僅次於管理局總部。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배는 우리가 해줄 수 있는 게, <color=#ffd34c>거기까지</color>라고 했어.","JPN":"ジジイは俺たちができるのは、<color=#ffd34c>そこまで</color>だと言ってた。","ENG":"The old chap said that <color=#ffd34c>this is as far as we go</color>.","TWN":"老頭說，我們能為你做的，就<color=#ffd34c>只有這些</color>了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저, 궁금한 건 많지만…….","JPN":"あの、気になることが沢山あるんですけど……","ENG":"I... have a lot of questions, but...","TWN":"那個，我有很多疑問……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"어떻게 제가 아카데미 편입생이라는 걸 알고 계셨어요? 그건 제 친구들 밖에 모를 텐데?","JPN":"私がアカデミーの編入生だって、なんで知ってるんですか？　これは私の友だちしか知らないはずです。","ENG":"How did you know I transferred to the Academy? That's only something my friends know.","TWN":"你怎麼知道我是學院插班生？除了我朋友之外應該沒人知道的？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시, 시끄러워!","JPN":"う、うるせえ！","ENG":"Sh-shut it!","TWN":"吵，吵死了！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아무튼 나중에 후회하지 말고, 내 말대로 하라구!","JPN":"とにかく、後で後悔しないで、俺の言うとおりにやれ！","ENG":"Anyway, just do as I say or you might regret it later!","TWN":"總之以後不想後悔的話，就照我的話去做！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저, 저기! 잠시만요!","JPN":"あ、あの！　待ってください！","ENG":"U-um! Wait!","TWN":"那，那個！等一下！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};